import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import {
  getElectionByConstituency,
  createElection,
  updateElection
} from "../../api/electionsApi";

function ElectionDashboard() {
  const { id } = useParams(); // constituency id
  const [election, setElection] = useState(null);
  const [form, setForm] = useState({});

  useEffect(() => {
    getElectionByConstituency(id).then(res => {
      if (res.data && res.data.id) {
        setElection(res.data);
      } else {
        setElection(null);
      }
    });
  }, [id]);

  // Explicit election creation
  const createNewElection = async () => {
    const res = await createElection({
      constituency_id: id
    });
    setElection(res.data);
    alert("Election created successfully");
  };

  // Update only AFTER creation
  const save = async () => {
    if (!election || !election.id) {
      alert("Please create an election first");
      return;
    }

    await updateElection(election.id, form);
    alert("Election details updated");
  };

  // ------------------------------
  // UI when NO election exists
  // ------------------------------
  if (!election) {
    return (
      <div>
        <h2>Election Management</h2>
        <p>No active election for this constituency.</p>

        <button onClick={createNewElection}>
          Create New Election
        </button>
      </div>
    );
  }

  // ------------------------------
  // UI when election EXISTS
  // ------------------------------
  return (
    <div>
      <h2>Election Management</h2>
      <p><b>Status:</b> {election.status}</p>

      <hr />

      <h3>Candidate Application Phase</h3>
      <label>Application Deadline</label>
      <br />
      <input
        type="datetime-local"
        onChange={e =>
          setForm({ ...form, application_deadline: e.target.value })
        }
      />

      <hr />

      <h3>Voter Registration Phase</h3>
      <label>Voter Registration Deadline</label>
      <br />
      <input
        type="datetime-local"
        onChange={e =>
          setForm({ ...form, voter_registration_deadline: e.target.value })
        }
      />

      <hr />

      <h3>Election Schedule</h3>
      <label>Election Start Time</label>
      <br />
      <input
        type="datetime-local"
        onChange={e =>
          setForm({ ...form, start_time: e.target.value })
        }
      />

      <br /><br />

      <label>Election End Time</label>
      <br />
      <input
        type="datetime-local"
        onChange={e =>
          setForm({ ...form, end_time: e.target.value })
        }
      />

      <br /><br />

      <button onClick={save}>Save Election Details</button>
    </div>
  );
}

export default ElectionDashboard;
